mapper.select:
select spaper.id as rowId ,spaper.period as period, spaper.roll as roll,csptt.name as thesisTypeName, spaper.start_page as startPage,spaper.end_page as endPage,sj.name as journalName,spaper.publish_date as publishDate, spaper.title as title,csy.name as pubYearName,spaper.data_status as dataStatus,spaper.publish_date as publishDate, spaper.first_author_name as firstAuthorName,spaper.corr_author_name as corrAuthorName, firstdept.name as firstAuthorDeptName,corrdept.name as corrAuthorDeptName,createuser.name as creatorName from srm_paper spaper left join ct_srm_year csy on csy.code=spaper.pub_year left join ct_srm_paper_thesis_type csptt on csptt.code=spaper.thesis_type left join ct_srm_dept fdept on fdept.id=spaper.dept_id
left join srm_journal sj on sj.code=spaper.journal left join ct_srm_journal_type csjt on csjt.code=spaper.journal_type left join ct_srm_reimbursement_way csrw on csrw.code=spaper.reim_way left join ct_srm_user createuser on createuser.id=spaper.creator left join ct_srm_user fuser on fuser.id=spaper.first_author_id left join ct_srm_user cuser on cuser.id=spaper.corr_author_id left join ct_srm_user puser on puser.id=spaper.proj_author left join ct_srm_class sclass on sclass.code=spaper.classCode left join ct_srm_product_projectsource sprojectsource on sprojectsource.code=spaper.proj_source_code left join ct_srm_discipline fdiscipline on fdiscipline.code=spaper.discipline left join ct_srm_discipline sdiscipline on sdiscipline.code=spaper.discipline2 left join ct_srm_discipline tdiscipline on tdiscipline.code=spaper.discipline3 left join ct_srm_unit_order csuo on csuo.code=spaper.our_unit_ranking left join ct_srm_dept firstdept on firstdept.id=spaper.first_author_dept_id left join ct_srm_dept corrdept on corrdept.id=spaper.corr_author_dept_id where (spaper.sub_user_id=#{paperDto.userId} or spaper.creator=#{paperDto.userId} or spaper.id in (SELECT paper_id FROM srm_paper_author WHERE author = #{paperDto.userId}) )
and spaper.title LIKE CONCAT('%', #{paperDto.title}, '%')
and spaper.sub_date >= #{paperDto.startDate}
and spaper.sub_date <= #{paperDto.endDate}
and spaper.journal = #{paperDto.journal}
and spaper.deptId = #{paperDto.deptId}
and spaper.biz_type= #{paperDto.bizType}
and spaper.data_status = #{paperDto.dataStatus}
order by spaper.id desc

select spaper.id as rowId ,spaper.period as period, spaper.roll as roll,csptt.name as thesisTypeName, spaper.start_page as startPage,spaper.end_page as endPage,sj.name as journalName,spaper.publish_date as publishDate, spaper.title as title,csy.name as pubYearName,spaper.data_status as dataStatus, spaper.first_author_name as firstAuthorName,spaper.corr_author_name as corrAuthorName, firstdept.name as firstAuthorDeptName,corrdept.name as corrAuthorDeptName,createuser.name as creatorName from srm_paper spaper left join ct_srm_year csy on csy.code=spaper.pub_year left join ct_srm_paper_thesis_type csptt on csptt.code=spaper.thesis_type left join ct_srm_dept fdept on fdept.id=spaper.dept_id
left join srm_journal sj on sj.code=spaper.journal left join ct_srm_journal_type csjt on csjt.code=spaper.journal_type left join ct_srm_reimbursement_way csrw on csrw.code=spaper.reim_way left join ct_srm_user createuser on createuser.id=spaper.creator left join ct_srm_user fuser on fuser.id=spaper.first_author_id left join ct_srm_user cuser on cuser.id=spaper.corr_author_id left join ct_srm_user puser on puser.id=spaper.proj_author left join ct_srm_class sclass on sclass.code=spaper.classCode left join ct_srm_product_projectsource sprojectsource on sprojectsource.code=spaper.proj_source_code left join ct_srm_discipline fdiscipline on fdiscipline.code=spaper.discipline left join ct_srm_discipline sdiscipline on sdiscipline.code=spaper.discipline2 left join ct_srm_discipline tdiscipline on tdiscipline.code=spaper.discipline3 left join ct_srm_unit_order csuo on csuo.code=spaper.our_unit_ranking left join ct_srm_dept firstdept on firstdept.id=spaper.first_author_dept_id left join ct_srm_dept corrdept on corrdept.id=spaper.corr_author_dept_id left join cf_srm_eaf_rec eafrec on eafrec.sys_no=spaper.sys_no and eafrec.check_rec_id=spaper.id where eafrec.step_no>1
and spaper.title LIKE CONCAT('%', #{paperDto.title}, '%')
and spaper.sub_date >= #{paperDto.startDate}
and spaper.sub_date <= #{paperDto.startDate}
and spaper.journal = #{paperDto.journal}
and spaper.deptId = #{paperDto.deptId}
and spaper.biz_type= #{paperDto.bizType}
and ( (spaper.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{paperDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where spaper.sys_no=seafrec.sys_no and seafrec.check_rec_id=spaper.id) and eafrec.checker_string LIKE CONCAT('%|', #{paperDto.userId}, '|%') and eafrec.check_datetime is not null) or (spaper.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{paperDto.userId}, '|%')) )
and spaper.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{paperDto.userId}, '|%')
and spaper.data_status=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{paperDto.userId}, '|%')
and spaper.data_status=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{paperDto.userId}, '|%')

select spa.author as id,spa.author_name as name,spa.title,spa.edu_degree as eduDegree,spa.edu_level as eduLevel,spa.author_dept_id as dept
from srm_paper_author spa
where spa.paper_id=#{parentId}

    and spa.is_corr_author=#{isCorrFlag}

order by spa.ranking Asc limit 1

select ply.id as id,ply.title as name from srm_paper_submission_apply ply
left join cf_srm_eaf_rec eafrec on eafrec.sys_no=ply.sys_no and eafrec.check_rec_id=ply.id
where eafrec.step_no>1 and
( ply.sub_user_id=#{userId}
  or ply.first_author_id=#{userId}
  or ply.corr_author_id=#{userId}
)
and "2"=(select eafrec2.check_result from cf_srm_eaf_rec eafrec2 where eafrec2.sys_no=ply.sys_no and eafrec2.check_rec_id=ply.id order by eafrec2.step_no desc limit 1)

select spsg.id as rowId,spsg.app_rowId as appRowId,spsg.note as note, csu.name as subUserName, spaper.sub_date as subDate , fuser.name as firstAuthorName,cuser.name as corrAuthorName, firstdept.name as firstAuthorDeptName,corrdept.name as corrAuthorDeptName, spsg.audit_status as auditStatus,spsg.data_status as dataStatus,
spaper.title as title,spaper.data_status as dataStatus, spaper.first_author_name as firstAuthorName,spaper.corr_author_name as corrAuthorName, firstdept.name as firstAuthorDeptName,corrdept.name as corrAuthorDeptName
from srm_paper_submission_grade spsg left join srm_paper spaper on spaper.id=spsg.app_rowId left join ct_srm_user csu on csu.id=spaper.sub_user_id
left join ct_srm_user fuser on fuser.id=spaper.first_author_id left join ct_srm_user cuser on cuser.id=spaper.corr_author_id left join ct_srm_dept firstdept on firstdept.id=spaper.first_author_dept_id left join ct_srm_dept corrdept on corrdept.id=spaper.corr_author_dept_id where spsg.expert=#{paperSubmissionExpertAuditDto.userId} and spsg.sys_no=#{paperSubmissionExpertAuditDto.sysNo}
and ply.title=#{paperSubmissionExpertAuditDto.title}
